def reload!
  @settings = {}
  load_defaults
  load_from_file if config_file_exists?
  load_from_env
  notify_reload_listeners
  self
end

def on_reload(&block)
  @reload_listeners ||= []
  @reload_listeners << block
end

def notify_reload_listeners
  @reload_listeners&.each(&:call)
end

